PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?person ?personLabel
WHERE {
  {
    ?person p:P166 ?statement .
    ?statement ps:P166 wd:Q19839211 .  # Golden Globe Best Actress - Limited Series
    ?statement pq:P976 wd:Q30751274 .  # Big Little Lies season 1
  }
  UNION
  {
    ?person p:P166 ?statement .
    ?statement ps:P166 wd:Q19839210 .  # Golden Globe Best Actor - Limited Series
    ?statement pq:P976 wd:Q30751274 .  # Big Little Lies season 1
  }
  ?person rdfs:label ?personLabel .
  FILTER(LANG(?personLabel) = "en")
}

